    {
      icon: CheckCircle2,
      label: "Available",
      value: available,
      sub: "ready for session",
      color: "text-[oklch(0.65_0.18_145)]",
      bg: "bg-[oklch(0.65_0.18_145)/8]",
      border: "border-[oklch(0.65_0.18_145)/20]",
