      border: fault > 0 ? "border-[oklch(0.65_0.22_25)/20]" : "border-border",
    },
    {
      icon: WifiOff,
      label: "Offline",
      value: offline,
      sub: "no connection",
      color: "text-muted-foreground",
      bg: "bg-muted/40",
      border: "border-border",
