@import "shadcn/tailwind.css";
@import "@fontsource-variable/geist";

@custom-variant dark (&:is(.dark *));

@theme inline {
    --font-heading: var(--font-sans);
    --font-sans: 'Geist Variable', sans-serif;
    --color-sidebar-ring: var(--sidebar-ring);
    --color-sidebar-border: var(--sidebar-border);
    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    --color-sidebar-accent: var(--sidebar-accent);
    --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
    --color-sidebar-primary: var(--sidebar-primary);
    --color-sidebar-foreground: var(--sidebar-foreground);
    --color-sidebar: var(--sidebar);
    --color-chart-5: var(--chart-5);
    --color-chart-4: var(--chart-4);
    --color-chart-3: var(--chart-3);
    --color-chart-2: var(--chart-2);
    --color-chart-1: var(--chart-1);
    --color-ring: var(--ring);
    --color-input: var(--input);
    --color-border: var(--border);
    --color-destructive: var(--destructive);
    --color-accent-foreground: var(--accent-foreground);
    --color-accent: var(--accent);
    --color-muted-foreground: var(--muted-foreground);
    --color-muted: var(--muted);
    --color-secondary-foreground: var(--secondary-foreground);
    --color-secondary: var(--secondary);
    --color-primary-foreground: var(--primary-foreground);
    --color-primary: var(--primary);
    --color-popover-foreground: var(--popover-foreground);
    --color-popover: var(--popover);
    --color-card-foreground: var(--card-foreground);
    --color-card: var(--card);
    --color-foreground: var(--foreground);
    --color-background: var(--background);
    --radius-sm: calc(var(--radius) * 0.6);
    --radius-md: calc(var(--radius) * 0.8);
    --radius-lg: var(--radius);
    --radius-xl: calc(var(--radius) * 1.4);
    --radius-2xl: calc(var(--radius) * 1.8);
    --radius-3xl: calc(var(--radius) * 2.2);
    --radius-4xl: calc(var(--radius) * 2.6);
}

/* ─── Light Mode ────────────────────────────────────────────────────────────── */
:root {
    --background: oklch(0.97 0.002 240);
    --foreground: oklch(0.14 0.01 240);
    --card: oklch(1 0 0);
    --card-foreground: oklch(0.14 0.01 240);
    --popover: oklch(1 0 0);
    --popover-foreground: oklch(0.14 0.01 240);
    --primary: oklch(0.55 0.20 240);
    --primary-foreground: oklch(0.98 0 0);
    --secondary: oklch(0.94 0.005 240);
    --secondary-foreground: oklch(0.25 0.01 240);
    --muted: oklch(0.94 0.005 240);
    --muted-foreground: oklch(0.52 0.01 240);
    --accent: oklch(0.94 0.005 240);
    --accent-foreground: oklch(0.25 0.01 240);
    --destructive: oklch(0.577 0.245 27.325);
    --border: oklch(0.89 0.006 240);
    --input: oklch(0.89 0.006 240);
    --ring: oklch(0.60 0.20 240);
    --chart-1: oklch(0.60 0.20 240);
    --chart-2: oklch(0.72 0.18 145);
    --chart-3: oklch(0.65 0.16 75);
    --chart-4: oklch(0.65 0.18 300);
    --chart-5: oklch(0.65 0.22 25);
    --radius: 0.625rem;
    --sidebar: oklch(0.985 0.002 240);
    --sidebar-foreground: oklch(0.14 0.01 240);
    --sidebar-primary: oklch(0.55 0.20 240);
    --sidebar-primary-foreground: oklch(0.98 0 0);
    --sidebar-accent: oklch(0.93 0.008 240);
    --sidebar-accent-foreground: oklch(0.25 0.01 240);
    --sidebar-border: oklch(0.89 0.006 240);
    --sidebar-ring: oklch(0.60 0.20 240);
}

/* ─── Dark Mode ─────────────────────────────────────────────────────────────── */
.dark {
    --background: oklch(0.115 0.008 240);
    --foreground: oklch(0.94 0.005 240);
    --card: oklch(0.155 0.010 240);
    --card-foreground: oklch(0.94 0.005 240);
    --popover: oklch(0.155 0.010 240);
    --popover-foreground: oklch(0.94 0.005 240);
    --primary: oklch(0.65 0.20 240);
    --primary-foreground: oklch(0.10 0.01 240);
    --secondary: oklch(0.22 0.012 240);
    --secondary-foreground: oklch(0.94 0.005 240);
    --muted: oklch(0.22 0.012 240);
    --muted-foreground: oklch(0.60 0.010 240);
    --accent: oklch(0.22 0.012 240);
    --accent-foreground: oklch(0.94 0.005 240);
    --destructive: oklch(0.65 0.22 25);
    --border: oklch(1 0 0 / 8%);
    --input: oklch(1 0 0 / 10%);
    --ring: oklch(0.60 0.20 240);
    --chart-1: oklch(0.65 0.20 240);
    --chart-2: oklch(0.72 0.18 145);
    --chart-3: oklch(0.72 0.16 75);
    --chart-4: oklch(0.68 0.18 300);
    --chart-5: oklch(0.68 0.22 25);
    --sidebar: oklch(0.135 0.010 240);
    --sidebar-foreground: oklch(0.94 0.005 240);
    --sidebar-primary: oklch(0.65 0.20 240);
    --sidebar-primary-foreground: oklch(0.10 0.01 240);
    --sidebar-accent: oklch(0.20 0.012 240);
    --sidebar-accent-foreground: oklch(0.94 0.005 240);
    --sidebar-border: oklch(1 0 0 / 8%);
    --sidebar-ring: oklch(0.60 0.20 240);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
  html {
    @apply font-sans;
  }
}

/* ─── Custom scrollbar (dark) ───────────────────────────────────────────────── */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: oklch(0.4 0.01 240 / 0.4);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: oklch(0.5 0.01 240 / 0.6);
}

/* ─── Recharts overrides ────────────────────────────────────────────────────── */
.recharts-tooltip-wrapper .recharts-default-tooltip {
  background: var(--card) !important;
  border: 1px solid var(--border) !important;
  border-radius: 8px !important;
}

/* ─── Leaflet overrides ─────────────────────────────────────────────────────── */
.leaflet-container {
  background: oklch(0.14 0.01 240) !important;
  font-family: var(--font-sans) !important;
  border-radius: 0.625rem;
}
.dark .leaflet-tile {
  filter: invert(1) hue-rotate(180deg) brightness(0.85) saturate(0.9);
}
.leaflet-control-attribution {
  font-size: 9px !important;
  opacity: 0.4 !important;
}
.leaflet-control-zoom a {
  background: var(--card) !important;
  color: var(--foreground) !important;
  border-color: var(--border) !important;
}

